# tests/performance/test_latency_sla.py
# Fast unit-level latency assertions for synchronous components
import pytest
import time
from myagent.prompt_builder import build_system_prompt, build_user_message
from myagent.response_parser import parse_tool_call_response

def test_prompt_building_under_10ms():
    """Prompt building must not become a latency contributor."""
    start = time.monotonic()
    for _ in range(100):
        build_system_prompt(user_context={"name": "test", "role": "analyst"})
        build_user_message("Summarize the attached document.", attachments=[])
    elapsed_ms = (time.monotonic() - start) * 1000 / 100
    assert elapsed_ms < 10, f"Prompt building took {elapsed_ms:.2f}ms per call (threshold: 10ms)"

def test_response_parsing_under_5ms():
    """Response parsing must not add measurable latency."""
    sample_response = {
        "choices": [{
            "message": {
                "tool_calls": [{
                    "id": "call_123",
                    "type": "function",
                    "function": {"name": "search", "arguments": '{"query": "test"}'}
                }]
            },
            "finish_reason": "tool_calls"
        }]
    }
    start = time.monotonic()
    for _ in range(1000):
        parse_tool_call_response(sample_response)
    elapsed_ms = (time.monotonic() - start) * 1000 / 1000
    assert elapsed_ms < 5, f"Response parsing took {elapsed_ms:.3f}ms per call (threshold: 5ms)"
